def transpose_2d(A):
    m = len(A)
    n = len(A[0])
    result = [[0] * m for _ in range(n)]
    for i in range(m):
        for j in range(n):
            result[j][i] = A[i][j]
    return result


import numpy as np

def transpose_nd(A, axes=None):
    A = np.asarray(A)
    if axes is None:
        axes = tuple(range(A.ndim - 1, -1, -1))
    return np.transpose(A, axes)
